def assess(record: dict) -> str:
    required = {"case_id", 'schema', 'row', 'catalog_ok'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if record["catalog_ok"] is True else "REJECT_UNKNOWN_FEATURE"

valid = {"case_id": "CASO-LIM-032-1A", **{'schema': {'numeric': ['amount_7d'], 'categorical': ['canal']}, 'row': {'amount_7d': 1.0, 'canal': 'app'}, 'catalog_ok': True}}
invalid = {"case_id": "CASO-LIM-032-1A", **{'schema': {'numeric': ['amount_7d']}, 'row': {'unknown_feat': 1}, 'catalog_ok': False}}
incomplete = {**valid}
incomplete.pop("schema")
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

def decide(record: dict) -> str:
    required = {"amount_7d", "canal", "case_id", "catalog_ok", "categorical", "numeric", "row", "schema"}
    missing = sorted(required - record.keys())
    if missing:
        return "REQUEST_CATALOG"
    ok = record["catalog_ok"] is True
    return "CONTINUE" if ok else "REJECT_UNKNOWN_FEATURE"

valid = {"case_id": "CASO-LIM-032-1A", **{'schema': {'numeric': ['amount_7d'], 'categorical': ['canal']}, 'row': {'amount_7d': 1.0, 'canal': 'app'}, 'catalog_ok': True}}
if "case_id" not in valid:
    valid = {"case_id": "VALID", **valid}
invalid = dict(valid)
if "catalog_ok" in invalid:
    invalid["catalog_ok"] = False
elif "observed_ms" in invalid and "target_ms" in invalid:
    invalid["observed_ms"] = invalid["target_ms"] + 50
elif "means_fraud" in invalid:
    invalid["means_fraud"] = True
elif "cache_authoritative" in invalid:
    invalid["cache_authoritative"] = True
elif "holdout" in invalid:
    invalid["holdout"] = 0
elif "jobs" in invalid:
    invalid["jobs"] = 0
elif "baseline_frozen" in invalid:
    invalid["baseline_frozen"] = False
elif "auto_fraud" in invalid:
    invalid["auto_fraud"] = True
elif "stages" in invalid:
    try:
        invalid["stages"] = list(reversed(list(invalid["stages"])))
    except Exception:
        pass
else:
    for k, v in list(invalid.items()):
        if k == "case_id":
            continue
        if isinstance(v, bool):
            invalid[k] = not v
            break
incomplete = {k: v for k, v in valid.items() if k != "schema"}
print(decide(valid), decide(invalid), decide(incomplete))

